sql:
SELECT watch_id, product_name, brand, model_number, serial
FROM watches
WHERE condition = 'Used';

SELECT brand 
FROM watches
WHERE watch_id = 1;

SELECT partner_id, partner_name, contact_name, email, phone, address
FROM partners
WHERE partner_name = 'GCI';

SELECT * FROM sales
WHERE sale_date BETWEEN '2023-01-01' AND '2023-01-31'
ORDER BY watch_id;

external_knowledge:
- 'timepiece labels' refers to the 'brand' of the watch in the database;
- 'more popular' suggests counting the frequency or number of items associated with each brand;
- 'pieces are in the collection' refers to the watches within the 'watches' table.

sql:
SELECT brand, COUNT(*) AS number_of_watches
FROM watches
GROUP BY brand;

SELECT *
FROM watches
INNER JOIN sales ON watches.watch_id = sales.watch_id;

SELECT product_name, brand, current_stock_id, warehouse
FROM watches
WHERE brand = 'Rolex' AND current_stock_id > 50;

SELECT models.model_number 
FROM suppliers 
INNER JOIN models ON suppliers.supplier_name = models.model_number;

SELECT image_url, watch_id
FROM gallery_images
WHERE image_type = 'side';
